def test_unauthenticated_request_creates_performance_review(api_base_url):
    payload = {
        "employee_id": "emp-001",
        "review_period": "2024-Q1",
        "rating": 4
    }
    resp = <request_helper>.post(
        f"{api_base_url}/api/performance-reviews",
        json=payload,
        headers={}
    )
    assert resp.status_code == 401
    assert <db_helper>.count_performance_reviews() == 0

def test_non_manager_role_forbidden_create_performance_review(auth_headers_employee, api_base_url):
    payload = {
        "employee_id": "emp-001",
        "review_period": "2024-Q1",
        "rating": 4
    }
    resp = <request_helper>.post(
        f"{api_base_url}/api/performance-reviews",
        json=payload,
        headers=auth_headers_employee
    )
    assert resp.status_code == 403
    assert <db_helper>.count_performance_reviews() == 0

def test_boundary_rating_below_minimum(auth_headers_manager, api_base_url):
    payload = {
        "employee_id": "emp-001",
        "review_period": "2024-Q1",
        "rating": 0
    }
    resp = <request_helper>.post(
        f"{api_base_url}/api/performance-reviews",
        json=payload,
        headers=auth_headers_manager
    )
    assert resp.status_code == 400
    assert "rating" in resp.json().get("errors", {})

def test_boundary_comments_field_max_length(auth_headers_manager, api_base_url):
    payload = {
        "employee_id": "emp-001",
        "review_period": "2024-Q1",
        "rating": 4,
        "comments": "x" * 500
    }
    resp = <request_helper>.post(
        f"{api_base_url}/api/performance-reviews",
        json=payload,
        headers=auth_headers_manager
    )
    assert resp.status_code in [200, 201]
